import React, { useState, useEffect } from 'react';
import { INITIAL_ACTIVITIES } from '../constants';
import { Activity } from '../types';

const ActivityFeed: React.FC = () => {
  const [activities, setActivities] = useState<Activity[]>(INITIAL_ACTIVITIES);

  // Simulate incoming activity
  useEffect(() => {
    const interval = setInterval(() => {
      const types: Activity['type'][] = ['purchase', 'rfq', 'listing'];
      const locations = ['UAE', 'China', 'India', 'Germany', 'USA', 'Netherlands'];
      const crops = ['Maize', 'Soybeans', 'Rice', 'Cashews', 'Coffee'];

      const newActivity: Activity = {
        id: Date.now().toString(),
        type: types[Math.floor(Math.random() * types.length)],
        timestamp: 'Just now',
        message: `Buyer from ${locations[Math.floor(Math.random() * locations.length)]} ${types[Math.floor(Math.random() * types.length)] === 'rfq' ? 'requested quote for' : 'purchased'} ${Math.floor(Math.random() * 400 + 50)} MT ${crops[Math.floor(Math.random() * crops.length)]}`,
        details: `$${(Math.random() * 1000 + 200).toFixed(2)}/MT • Trade Desk Confirmed`
      };

      setActivities(prev => [newActivity, ...prev].slice(0, 10));
    }, 12000);
    return () => clearInterval(interval);
  }, []);

  const getIcon = (type: Activity['type']) => {
    switch(type) {
      case 'purchase': return '🟢';
      case 'rfq': return '🟠';
      case 'listing': return '🔵';
      default: return '⚪';
    }
  };

  return (
    <section className="py-16 px-4 max-w-[1400px] mx-auto">
      <div className="flex justify-between items-center mb-8">
        <div className="flex items-center gap-4 flex-1">
          <h2 className="text-2xl font-bold whitespace-nowrap">LIVE MARKET ACTIVITY</h2>
          <div className="h-px bg-border flex-1 border-dashed border-t"></div>
        </div>
        <div className="flex items-center gap-2 ml-4">
          <span className="w-2 h-2 rounded-full bg-primary animate-ping"></span>
          <span className="text-primary text-[11px] font-bold">47 TRADERS ONLINE</span>
        </div>
      </div>

      <div className="bg-surface border border-border rounded-xl overflow-hidden divide-y divide-border">
        {activities.map((act) => (
          <div key={act.id} className="p-4 hover:bg-surfaceHover transition-colors animate-in fade-in slide-in-from-top-4 duration-500">
            <div className="flex flex-col md:flex-row md:items-center justify-between gap-2">
              <div className="flex items-start md:items-center gap-3">
                <span className="text-lg leading-none">{getIcon(act.type)}</span>
                <span className="text-textMuted text-[11px] font-mono whitespace-nowrap uppercase">{act.timestamp}</span>
                <p className="text-white text-sm font-semibold tracking-wide">{act.message}</p>
              </div>
              <div className="flex items-center gap-2 pl-8 md:pl-0">
                <span className="text-textMuted text-[13px]">{act.details}</span>
              </div>
            </div>
          </div>
        ))}
      </div>

      <div className="mt-8 text-center">
        <button className="text-textMuted hover:text-primary text-xs uppercase tracking-widest font-bold">
          VIEW FULL ACTIVITY LOG →
        </button>
      </div>
    </section>
  );
};

export default ActivityFeed;

