import React, { useState, useEffect } from 'react';

const CommandPalette: React.FC = () => {
  const [isOpen, setIsOpen] = useState(false);

  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
      if ((e.metaKey || e.ctrlKey) && e.key === 'k') {
        e.preventDefault();
        setIsOpen(prev => !prev);
      }
      if (e.key === 'Escape') setIsOpen(false);
    };
    window.addEventListener('keydown', handleKeyDown);
    return () => window.removeEventListener('keydown', handleKeyDown);
  }, []);

  if (!isOpen) return null;

  return (
    <div className="fixed inset-0 z-[100] flex items-center justify-center p-4">
      <div className="absolute inset-0 bg-black/80 backdrop-blur-sm" onClick={() => setIsOpen(false)}></div>
      <div className="relative w-full max-w-[600px] bg-surface border-2 border-primary/50 rounded-2xl shadow-2xl shadow-primary/20 animate-in zoom-in-95 duration-200">
        <div className="p-4 border-b border-border">
          <input 
            autoFocus
            type="text" 
            placeholder="Type a command or search..." 
            className="w-full bg-transparent border-none outline-none text-xl font-mono text-white placeholder:text-textMuted"
          />
        </div>

        <div className="p-4 max-h-[400px] overflow-y-auto">
          <div className="mb-6">
            <h5 className="text-[10px] font-bold text-textMuted uppercase mb-3 px-2 tracking-widest">Recent Activity</h5>
            <div className="space-y-1">
              {['Track order #12345', 'Browse maize listings', 'Export documentation help'].map((item, i) => (
                <button key={i} className="w-full text-left px-2 py-2 hover:bg-primary/10 hover:text-primary rounded text-sm transition-colors flex justify-between items-center group">
                  <span>→ {item}</span>
                  <span className="text-[10px] text-textMuted opacity-0 group-hover:opacity-100 uppercase font-bold">Recent</span>
                </button>
              ))}
            </div>
          </div>

          <div className="mb-6">
            <h5 className="text-[10px] font-bold text-textMuted uppercase mb-3 px-2 tracking-widest">Quick Actions</h5>
            <div className="space-y-1">
              {[
                { label: 'Browse Marketplace', key: '⌘B', icon: '🔍' },
                { label: 'Initiate RFQ', key: '⌘R', icon: '📝' },
                { label: 'Trade Desk', key: '⌘T', icon: '💼' },
                { label: 'Shipment Log', key: '⌘S', icon: '🚢' },
              ].map((item, i) => (
                <button key={i} className="w-full text-left px-2 py-3 hover:bg-primary/10 hover:text-primary rounded text-sm transition-colors flex justify-between items-center">
                  <div className="flex items-center gap-3">
                    <span className="text-base">{item.icon}</span>
                    <span className="font-semibold tracking-wide">{item.label}</span>
                  </div>
                  <span className="text-[11px] font-mono text-textMuted bg-background px-1.5 py-0.5 rounded">{item.key}</span>
                </button>
              ))}
            </div>
          </div>
        </div>

        <div className="p-3 border-t border-border bg-background/50 text-[10px] text-textMuted flex justify-between rounded-b-2xl">
          <span>Arrows to navigate, Enter to select</span>
          <span>Esc to close</span>
        </div>
      </div>
    </div>
  );
};

export default CommandPalette;

import React, { useState } from 'react';
