                     </div>
                  </div>
               </div>
            </div>
          </div>
        );
      case 'dashboard':
      default:
        return (
          <>
            <Hero onRfqClick={() => setCurrentView('rfq')} onBuyClick={() => setCurrentView('marketplace')} />
